/**
 * Pre-main starter cost library expansion script.
 *
 * Creates 4 new seed files and appends to 3 existing ones.
 * Safe to re-run: skips any item whose id already exists in the file.
 *
 * Usage:
 *   node scripts/expandStarterLibraryPreMain.mjs
 */
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.join(__dirname, '..');
const SEEDS_DIR = path.join(ROOT, 'src/features/estimating/data/starterCostLibrary/seeds');
const MAT_DIR = path.join(SEEDS_DIR, 'materials');
const EQ_DIR = path.join(SEEDS_DIR, 'equipment');

const NOTES = 'Starter placeholder only. Verify local supplier pricing before proposal.';

function readExisting(filePath) {
  if (!fs.existsSync(filePath)) return [];
  try {
    const items = JSON.parse(fs.readFileSync(filePath, 'utf8'));
    if (!Array.isArray(items)) throw new Error('not an array');
    return items;
  } catch (e) {
    throw new Error(`Failed to read ${filePath}: ${e.message}`);
  }
}

function writeFile(filePath, items) {
  fs.mkdirSync(path.dirname(filePath), { recursive: true });
  fs.writeFileSync(filePath, JSON.stringify(items, null, 2) + '\n', 'utf8');
}

function mergeAndWrite(filePath, newItems) {
  const existing = readExisting(filePath);
  const existingIds = new Set(existing.map((i) => i.id));
  const added = [];
  for (const item of newItems) {
    if (!existingIds.has(item.id)) {
      existing.push(item);
      added.push(item.id);
    }
  }
  writeFile(filePath, existing);
  return { total: existing.length, added: added.length };
}

// ---------------------------------------------------------------------------
// Item factories
// ---------------------------------------------------------------------------

function mat(id, category, subcategory, csiDivision, csiSection, name, description, unit, commonUnits, cost, tags) {
  return {
    costConfidence: 'placeholder',
    pricingRequired: true,
    notes: NOTES,
    defaultUnitCost: cost,
    id,
    type: 'material',
    category,
    subcategory,
    csiDivision,
    csiSection,
    name,
    description,
    unit,
    commonUnits,
    tags,
  };
}

function eq(id, category, subcategory, csiDivision, csiSection, name, description, unit, commonUnits, cost, tags) {
  return {
    costConfidence: 'placeholder',
    pricingRequired: true,
    notes: NOTES,
    defaultUnitCost: cost,
    id,
    type: 'equipment',
    category,
    subcategory,
    csiDivision,
    csiSection,
    name,
    description,
    unit,
    commonUnits,
    cost,
    tags,
  };
}

