// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

function main() {
  const results = [];

  // New files
  const newFiles = [
    { path: path.join(MAT_DIR, 'specialties.json'), items: SPECIALTIES, label: 'materials/specialties.json' },
    { path: path.join(MAT_DIR, 'general-conditions.json'), items: GENERAL_CONDITIONS_MAT, label: 'materials/general-conditions.json' },
    { path: path.join(EQ_DIR, 'general-conditions.json'), items: EQUIP_GENERAL_CONDITIONS, label: 'equipment/general-conditions.json' },
    { path: path.join(EQ_DIR, 'safety-access.json'), items: EQUIP_SAFETY_ACCESS, label: 'equipment/safety-access.json' },
  ];

  for (const { path: filePath, items, label } of newFiles) {
    const r = mergeAndWrite(filePath, items);
    results.push(`  ${label}: ${r.added} added (total ${r.total})`);
  }

  // Existing files (append)
  const appendFiles = [
    { path: path.join(MAT_DIR, 'mep.json'), items: MEP_APPEND, label: 'materials/mep.json' },
    { path: path.join(MAT_DIR, 'sitework.json'), items: SITEWORK_APPEND, label: 'materials/sitework.json' },
    { path: path.join(MAT_DIR, 'roofing-exterior.json'), items: ROOFING_APPEND, label: 'materials/roofing-exterior.json' },
  ];

  for (const { path: filePath, items, label } of appendFiles) {
    const r = mergeAndWrite(filePath, items);
    results.push(`  ${label}: ${r.added} added (total ${r.total})`);
  }

  console.log('\nExpansion complete:');
  for (const r of results) console.log(r);
  console.log('\nNext step: node scripts/generateStarterCostLibrary.mjs');
}

main();
